/// Test zero TTL edge case
#[test]
fn test_zero_ttl_expiry() {
    // With TTL=0, expiry_block == commit_block
    let commit_block = 100u64;
    let ttl = 0u64;
    let expiry_block = commit_block + ttl; // = 100

    // At commit_block - NOT expired
    assert!(100 <= expiry_block, "At commit block with TTL=0 should NOT be expired");

    // Next block - EXPIRED
    assert!(!(101 <= expiry_block), "Block after commit with TTL=0 should BE expired");
}

